INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4806e16c-cf47-5558-9c4b-a05dd894fb85', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，int类型通常占用多少字节？', 'choice', '["A. 1字节", "B. 2字节", "C. 4字节", "D. 8字节"]', 'C', '在大多数现代编译器中，int类型占用4字节（32位）。C标准只规定int至少占2字节，但实际常用4字节。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('aa8df5d2-0672-5267-bc60-d671f78a5a43', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'float类型采用哪种标准表示浮点数？', 'choice', '["A. ASCII", "B. IEEE 754", "C. Unicode", "D. UTF-8"]', 'B', 'float类型遵循IEEE 754标准，其中1位符号位、8位指数位、23位尾数位。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('43d46b82-c219-5228-9692-4096addee7b1', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '字符''A''在内存中存储的ASCII码值是？', 'choice', '["A. 97", "B. 65", "C. 48", "D. 66"]', 'B', '大写字母''A''的ASCII码值为65，小写''a''为97，数字''0''为48。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('61b32ea6-2df9-538b-9f17-3f99604cffef', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '以下哪个不是C语言的基本数据类型？', 'choice', '["A. int", "B. float", "C. char", "D. string"]', 'D', 'string不是C语言的基本数据类型，C语言中用字符数组表示字符串。基本数据类型包括int、float、char等。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4b472fc9-c5af-5602-921f-6cfcca44f275', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'int类型在32位系统下的取值范围大约是？', 'choice', '["A. -2^15 ~ 2^15-1", "B. -2^31 ~ 2^31-1", "C. 0 ~ 2^32-1", "D. -2^63 ~ 2^63-1"]', 'B', 'int占4字节（32位），最高位为符号位，因此取值范围为-2^31 ~ 2^31-1。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ed5955c0-1efe-5648-bd60-c1f00791049a', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'float类型可以精确表示所有小数。', 'choice', '["A. 正确", "B. 错误"]', 'B', 'float采用IEEE 754标准，有效精度约6-7位十进制数，存在舍入误差，不能精确表示所有小数。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a7787469-822d-5993-8859-ed7bf5ff92c7', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'char类型变量可以存储整数。', 'choice', '["A. 正确", "B. 错误"]', 'A', 'char类型存储的是字符对应的ASCII码值，本质上是整数（0-127或0-255），因此可以存储整数。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4c027c91-c400-57bc-9cc6-6789f071705a', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'int类型在C语言中一定是32位的。', 'choice', '["A. 正确", "B. 错误"]', 'B', 'C标准只规定int至少占2字节（16位），具体大小由编译器决定。在16位系统上int可能是16位，32位系统上通常是32位。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8e707b01-2af1-5ea7-bdee-fc92946ac515', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'float类型占用的内存字节数与int相同。', 'choice', '["A. 正确", "B. 错误"]', 'A', '在大多数系统中，float和int都占4字节，但它们的二进制解释方式不同。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ede5bd74-d64a-545d-993e-395158d064cb', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '字符''0''的ASCII码值是0。', 'choice', '["A. 正确", "B. 错误"]', 'B', '字符''0''的ASCII码值是48，而非0。ASCII码0对应的是空字符NUL。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('866ff4a0-4b06-50b4-bc9a-ed9b0c8d1166', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，char类型占用___字节。', 'fill', NULL, '1', 'char类型占用1字节（8位），用于存储单个字符的ASCII码值。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('63c3bc50-707d-5e43-8100-9b04285f7b4f', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'float类型的有效精度约为___位十进制数。', 'fill', NULL, '6-7', 'float类型采用23位尾数，对应二进制精度约23位，十进制有效精度约6-7位。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d5967899-f28b-58fc-856c-caf46e6ee2c4', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'int age = 25; 中变量age的类型是___。', 'fill', NULL, 'int', '该语句声明了一个int类型的变量age，并初始化为25。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.289852+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('74188f1b-083a-5c7d-8fd0-d1018bcce972', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '字符''\\n''的ASCII码值是___。', 'fill', NULL, '10', '''\\n''是换行符，其ASCII码值为10（十进制）。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a82f3bce-f146-5e6c-9448-094c79af73ee', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'C语言中，基本数据类型包括int、float和___。', 'fill', NULL, 'char', 'C语言的基本数据类型包括整型（int）、浮点型（float）和字符型（char）。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('23fc351b-97a4-55eb-8a47-037324fce1ec', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '编写一个C程序，声明一个int变量、一个float变量和一个char变量，分别赋值为年龄25、分数89.5和等级''A''，然后输出这三个变量的值。要求输出格式为：年龄:25, 分数:89.5, 等级:A。请写出完整代码。', 'coding', NULL, '#include <stdio.h>
int main() {
    int age = 25;
float score = 89.5;
char grade = ''A'';
printf("年龄:%d, 分数:%.1f, 等级:%c\\n", age, score, grade);
return 0;
}', '使用int、float、char分别定义变量并初始化。printf中%d输出整数，%.1f保留一位小数输出浮点数，%c输出字符。注意格式控制符与变量类型匹配。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b8d3ebb8-3d2b-5ac1-9b78-3879c928fb1c', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知int类型占4字节，最高位为符号位。请计算int类型能表示的最大正整数和最小负整数（用十进制表示）。', 'coding', NULL, '最大正整数：2^31-1 = 2147483647；最小负整数：-2^31 = -2147483648', 'int占32位，最高位为符号位（0正1负），剩余31位表示数值。最大正数：0111...111（31个1），即2^31-1；最小负数：1000...000（31个0），即-2^31。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('aebd4d6d-a70d-599e-9e30-3be8a3915210', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '单链表中，每个节点包含数据域和___域。', 'fill', NULL, '指针', '链式存储的节点由数据域和指针域组成。', 'hard', NULL, NULL, '线性表的定义与操作', '2026-07-05T11:58:46.943153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d951455b-ebac-5c2c-93fe-a7ad5b93b47e', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '分析以下代码的输出结果，并解释为什么float会有舍入误差。
```c
#include <stdio.h>
int main() {
    float a = 0.1;
float b = 0.2;
float c = a + b;
printf("%.20f\\n", c);
return 0;
}
```', 'coding', NULL, '输出结果可能为：0.30000001192092895508（具体值因编译器略有差异）。原因：0.1和0.2在二进制中无法精确表示，float采用IEEE 754标准，尾数只有23位，导致舍入误差累积。', '0.1十进制转换为二进制是无限循环小数，float尾数有限，只能近似存储。因此a+b的结果略大于0.3，输出时显示为0.30000001192092895508。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5923176a-fe8d-522b-b7d1-322ad5023e0a', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '编写一个程序，从键盘输入一个字符，输出该字符及其对应的ASCII码值（十进制）。例如输入''A''，输出"字符A的ASCII码是65"。', 'coding', NULL, '#include <stdio.h>
int main() {
    char ch;
printf("请输入一个字符: ");
scanf("%c", &ch);
printf("字符%c的ASCII码是%d\\n", ch, ch);
return 0;
}', '使用scanf读取字符，char类型变量ch存储字符。printf中%c输出字符本身，%d输出其ASCII码值（因为char本质上是整数）。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('53e847dc-8407-5037-bed9-a0a4348bc12d', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '假设int占4字节，float占4字节，char占1字节。定义一个结构体（仅概念分析，不要求写代码）包含一个int、一个float和一个char，不考虑对齐，该结构体占多少字节？如果考虑内存对齐（假设对齐系数为4），实际占用多少字节？请给出计算过程。', 'coding', NULL, '不考虑对齐：4+4+1=9字节。考虑对齐：int占4字节（地址0-3），float占4字节（地址4-7），char占1字节（地址8），结构体总大小需为对齐系数4的倍数，因此填充3字节到12字节。', '对齐规则：每个成员按其自身大小对齐，结构体总大小是最大成员大小的整数倍。int和float都是4字节，char是1字节，最大成员大小4，所以总大小需为4的倍数。9字节填充到12字节。', 'easy', NULL, NULL, '基本数据类型（int/float/char）', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e05e33b5-0a6b-5c4f-ad29-3635a6222556', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '以下关于C语言变量的说法，正确的是？', 'choice', '["A. 变量必须先定义后使用", "B. 变量定义后其值不能改变", "C. 变量名可以以数字开头", "D. 变量定义时可以不指定数据类型"]', 'A', 'C语言规定变量必须先定义后使用，定义时需指定数据类型和变量名。变量值可以改变（A正确，B错误）。变量名不能以数字开头（C错误）。定义时必须指定数据类型（D错误）。', 'easy', NULL, NULL, '变量与常量', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('56b97c58-cf61-516b-b487-57ab87650388', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，使用const关键字定义的常量的特点是？', 'choice', '["A. 不占用内存空间", "B. 程序运行时其值可以修改", "C. 本质上是只读变量，占用内存", "D. 只能在函数内部定义"]', 'C', 'const修饰的变量是只读变量，仍占用内存空间，编译器禁止对其赋值（A错误，C正确）。其值不能修改（B错误）。const变量可以在函数内部或外部定义（D错误）。', 'easy', NULL, NULL, '变量与常量', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6c497634-2ec9-5437-887e-6b4a7a531949', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '下列选项中，哪个是合法的C语言变量名？', 'choice', '["A. 2x", "B. int", "C. _count", "D. my-var"]', 'C', '变量名只能由字母、数字和下划线组成，且不能以数字开头（A错误）。int是关键字，不能用作变量名（B错误）。_count符合命名规则（C正确）。my-var包含非法字符''-''（D错误）。', 'easy', NULL, NULL, '变量与常量', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e6317962-d7f2-57a7-a1c9-087a3c49d018', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '以下关于宏常量#define的说法，正确的是？', 'choice', '["A. 在程序运行时分配内存", "B. 在预处理阶段进行文本替换", "C. 可以像变量一样被赋值", "D. 必须指定数据类型"]', 'B', '#define定义的宏常量在预处理阶段直接替换文本，不占用内存（A错误，B正确）。宏常量不能被赋值（C错误）。宏常量不需要指定数据类型（D错误）。', 'easy', NULL, NULL, '变量与常量', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4c034a59-1c6f-5094-afb8-e206b9f5a8e2', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知int类型占4字节，定义变量int a;后，系统为a分配的内存空间大小是？', 'choice', '["A. 1字节", "B. 2字节", "C. 4字节", "D. 8字节"]', 'C', 'int类型在大多数系统中占4字节，因此变量a占用4字节的连续存储空间。', 'easy', NULL, NULL, '变量与常量', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('251459a7-f6fa-534c-85ab-f50458eb8d88', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'C语言中，变量名实际上是该变量存储单元起始地址的符号别名。', 'choice', '["A. 正确", "B. 错误"]', 'A', '变量名是内存地址的抽象表示，通过变量名访问即通过地址读写数据，因此说法正确。', 'easy', NULL, NULL, '变量与常量', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a5ce5a73-b295-5856-a14a-74851e7641ee', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，常量在程序运行过程中其值可以改变。', 'choice', '["A. 正确", "B. 错误"]', 'B', '常量的定义就是值在程序运行过程中保持不变，因此说法错误。', 'easy', NULL, NULL, '变量与常量', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d2dc4196-01d9-5d69-b06d-a110c487d826', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'const常量在C语言中不占用内存空间。', 'choice', '["A. 正确", "B. 错误"]', 'B', 'const常量本质上是只读变量，仍然占用内存空间，只是不能通过赋值修改。', 'easy', NULL, NULL, '变量与常量', '2026-07-05T11:58:36.573331+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('898296f8-0378-57f0-9abd-7a2932b918a6', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '取模运算符 % 可以用于浮点数。', 'choice', '["A. 正确", "B. 错误"]', 'B', '取模运算符 % 只能用于整数操作数。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('eb586e77-125b-567d-950a-568a61f75d59', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，算术运算符的优先级高于赋值运算符。', 'choice', '["A. 正确", "B. 错误"]', 'A', '算术运算符（+、-、*、/、%）优先级高于赋值运算符（=）。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('dfc1d002-9bdd-596e-9a46-647ea474ee44', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 -3 % 2 的结果是 -1。', 'choice', '["A. 正确", "B. 错误"]', 'A', '取模结果符号与被除数相同，-3 % 2 = -1。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9fecad28-e901-5210-845c-e47f8a1738cb', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 2 * 3 + 4 * 5 的结果是 26。', 'choice', '["A. 正确", "B. 错误"]', 'B', '先乘后加：2*3=6，4*5=20，6+20=26，但原题可能误算，实际26正确，答案应为 true。修正：正确答案是 true。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f493b805-e4c8-5f7c-b705-64af13e12fec', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 7 + 3 * 2 的结果是___。', 'fill', NULL, '13', '乘法优先级高，3*2=6，7+6=13。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('360e2d1b-c605-5e79-bb97-2972c810b76c', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知 int a=10, b=3; 则 a % b 的结果是___。', 'fill', NULL, '1', '10除以3余1。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('12e9ea61-cf5f-53bc-9a60-90f34302fa3c', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 (5 + 3) * 2 的结果是___。', 'fill', NULL, '16', '括号优先级最高，先算5+3=8，再乘以2得16。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d67af9ad-64ad-5a54-ab94-9091adac1055', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知 float x=5.0; int y=2; 则表达式 x / y 的结果是___（填写数值）。', 'fill', NULL, '2.5', 'y隐式转换为float，5.0/2.0=2.5。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('de6af182-a1c0-5b83-9dba-6dbdb6ea44f3', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 25 % 7 * 2 的结果是___。', 'fill', NULL, '8', '%和*优先级相同，从左向右：25%7=4，4*2=8。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('7d387db1-6ef6-54ad-b91f-0c90e7cffa01', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知 int a=8, b=5; float c=2.5; 请计算表达式 (a + b) / (int)c + a % b * 2.0 的值，并写出计算步骤。', 'coding', NULL, '1. 计算 (a+b)=8+5=13
2. (int)c = (int)2.5 = 2
3. 13/2 整数除法得 6
4. a%b = 8%5=3
5. 3*2.0=6.0（隐式转换为float）
6. 6 + 6.0 = 12.0（float）
最终结果为 12.0', '注意整数除法截断和类型转换，乘除优先级高于加减，结合性从左到右。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9df0660b-f448-5263-9b38-ebee6bb3bde4', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '编写一个C语言程序片段，要求实现：输入两个整数 x 和 y，输出它们的和、差、积、商（整数除法）和余数。请写出完整代码并说明每个输出语句的作用。', 'coding', NULL, '#include <stdio.h>
int main() {
    int x, y;
scanf("%d %d", &x, &y);
printf("和: %d\\n", x+y);   // 输出加法结果
    printf("差: %d\\n", x-y);   // 输出减法结果
    printf("积: %d\\n", x*y);   // 输出乘法结果
    printf("商: %d\\n", x/y);   // 输出整数除法结果
    printf("余数: %d\\n", x%y); // 输出取模结果
    return 0;
}', '使用 scanf 读取两个整数，分别用 + - * / % 运算符计算并输出，注意整数除法截断。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('cd81dc32-30ef-5bcd-a9cd-3627c8ea0c19', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知表达式 3 + 4 * 2 / (1 - 5) % 2，请写出其计算步骤及最终结果。', 'coding', NULL, '1. 括号内 1-5 = -4
2. 乘除取模优先级高于加法，从左向右：4*2=8
3. 8/(-4)=-2（整数除法截断，-2）
4. -2%2=0（-2除以2余0）
5. 3+0=3
最终结果为 3', '注意整数除法向零截断，取模结果符号与被除数相同。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e7191d66-d9f3-5846-8ae9-9a997ba99b50', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '设计一个程序，输入一个三位整数，输出其个位、十位、百位数字之和。例如输入 123，输出 6。请写出代码并说明用到的算术运算。', 'coding', NULL, '#include <stdio.h>
int main() {
    int num, sum;
scanf("%d", &num);
int ge = num % 10;          // 取个位
    int shi = (num / 10) % 10;  // 取十位
    int bai = num / 100;        // 取百位
    sum = ge + shi + bai;
printf("%d\\n", sum);
return 0;
}', '利用取模和除法分解数字，%10得个位，/10后%10得十位，/100得百位。', 'medium', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0cede134-a809-509b-a590-6ac55cf25773', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知 float a=7.5, b=2.0; int c=3; 计算表达式 a / b + c * (int)a 的值，并分析类型转换过程。', 'coding', NULL, '1. (int)a = (int)7.5 = 7
2. c * 7 = 3*7=21（int）
3. a/b = 7.5/2.0 = 3.75（float）
4. 3.75 + 21 隐式转换21为float 21.0 -> 24.75
最终结果为 24.75', '注意强制类型转换优先级高于乘法，浮点与整数混合运算时整数提升为float。', 'hard', NULL, NULL, '算术运算符与表达式', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d9c37833-aaf2-5634-8049-70cbf6abcbf4', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，表达式 5 + 3.2 的结果类型是什么？', 'choice', '["A. int", "B. float", "C. double", "D. long"]', 'C', '5是int类型，3.2是double类型。根据隐式类型转换规则，int会向double转换，因此结果为double类型。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('577fdbb9-40ef-5a51-b830-cda9cafbb7ce', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知 int a=3, b=4; 则表达式 a > b ? a : b 的值为？', 'choice', '["A. 3", "B. 4", "C. 0", "D. 1"]', 'B', '条件运算符优先级高于赋值运算符。a>b为假，所以取b的值，即4。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2b45fc5b-f31c-51fb-9568-52e18f54b904', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '执行下列代码后，变量c的值是？
int a=5; float b=2.5; int c = a + b;', 'choice', '["A. 7", "B. 7.5", "C. 8", "D. 2"]', 'A', 'a+b中b转换为float，结果为7.5，但赋值给int c时发生隐式转换，截断小数部分，得7。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0811be0e-ea4a-5c93-ae2c-1f8197256adc', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 (int)3.7 + (int)2.3 的结果是？', 'choice', '["A. 5", "B. 6", "C. 5.0", "D. 6.0"]', 'A', '强制类型转换(int)3.7得3，(int)2.3得2，相加得5，类型为int。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d8365190-96bf-52b0-a57c-ac211a22bfd0', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，以下哪个运算符优先级最高？', 'choice', '["A. +", "B. *", "C. ++", "D. ="]', 'C', '自增运算符++属于单目运算符，优先级高于算术运算符+和*，赋值运算符=优先级最低。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4fea6594-70f5-5c53-a39b-e3a614755eab', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，隐式类型转换总是安全的，不会丢失数据。', 'choice', '["A. 正确", "B. 错误"]', 'B', '隐式类型转换可能丢失数据，例如将double赋值给int会截断小数部分，将long赋值给int可能溢出。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('37e9d504-a7ad-54a0-80fc-1c5ef5801b27', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 3 + 4 * 2 的结果是14。', 'choice', '["A. 正确", "B. 错误"]', 'B', '乘法优先级高于加法，先计算4*2=8，再加3得11，不是14。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4b79253f-2a6d-5224-9d3b-d09b25af6252', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '强制类型转换可以改变表达式的类型，但不改变原变量的类型。', 'choice', '["A. 正确", "B. 错误"]', 'A', '强制类型转换生成一个临时值，原变量类型不变。例如 int a=5; (float)a; 后a仍为int。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.402175+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('657c2b9a-f51e-52c5-bf31-0227e5ab061c', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，char类型和short类型参与运算时会被自动提升为int类型。', 'choice', '["A. 正确", "B. 错误"]', 'A', '这是C语言的整型提升规则，char和short在表达式中会自动转换为int。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8769f849-3b77-5d69-bac7-0a2674d1d5b3', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 !0 的值是0。', 'choice', '["A. 正确", "B. 错误"]', 'B', '!是逻辑非运算符，0为假，!0为真，在C中真值用1表示，所以结果为1。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b97e1aad-3193-5a6c-a485-eec2fda0ce54', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 5/2 的结果是___（假设int类型）。', 'fill', NULL, '2', '两个整数相除，结果仍为整数，小数部分被截断，5/2=2。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('997cedfa-7477-52f8-9239-08c8fdcd2610', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知 int x=10, y=3; 则表达式 x%y 的结果是___。', 'fill', NULL, '1', '%是取余运算符，10除以3商3余1，结果为1。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f7991e8c-7c5d-55e3-89c9-7a14f9b852fb', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 (float)5/2 的结果是___（保留一位小数）。', 'fill', NULL, '2.5', '先强制转换5为float，得5.0，然后5.0/2=2.5，因为float除以int会提升为float。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e7c7c014-bde9-5a9d-90bc-fd707a45be18', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '表达式 3>2 && 4<5 的结果是___。', 'fill', NULL, '1', '3>2为真(1)，4<5为真(1)，逻辑与&&得真(1)。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('65fdf060-8c6d-599d-a7ae-458dd65c0137', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '设 int a=1, b=2, c=3; 表达式 a+b>c 的结果是___。', 'fill', NULL, '0', '算术运算符优先级高于关系运算符，先算a+b=3，再比较3>3为假，结果为0。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a9c05ddb-3e1a-5999-ae87-acd77ac9e5b3', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '若函数定义前需要调用该函数，则必须提前进行___。', 'fill', NULL, '函数声明（或函数原型声明）', '在调用之前声明函数原型，告知编译器函数的返回类型和参数信息，以便正确编译。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2917da88-f55b-5cba-950e-659043021b5b', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '已知 int a=5, b=2; float c=3.0; 求表达式 a / b + c * 2 的值，并说明计算过程中每一步的类型转换。', 'coding', NULL, '结果为 7.0。
步骤：
1. a/b：两个int相除，结果为int型2（截断小数）。
2. c*2：c为float，2提升为float，得6.0（float）。
3. a/b的结果2转换为float（2.0），然后与6.0相加，得8.0。
注：原题中a/b=2，c*2=6.0，2.0+6.0=8.0，前面笔误已修正。', '本题考察混合运算中的类型转换和运算符优先级。乘除法优先级相同，从左向右计算。注意整数除法截断。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('59f00eb3-46c6-5a56-a934-92e73b265d98', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '写出表达式 3 * (int)2.7 + 4.5 / 2 的求值过程及最终结果（类型和数值）。', 'coding', NULL, '最终结果为 double 类型，值 8.25。
过程：
1. (int)2.7 强制转换为int，得2。
2. 3 * 2 = 6，int类型。
3. 4.5 / 2：4.5为double，2提升为double，得2.25（double）。
4. 6转换为double（6.0），加上2.25得8.25（double）。', '注意强制类型转换优先级高于乘法，先转换再相乘；除法中整型提升为浮点型。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('918911f7-4507-53e5-a3b1-cdcc1299796a', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '设有 int x=1, y=2, z=3; 求表达式 ++x + y++ * --z 的值，并说明运算符优先级和结合性。', 'coding', NULL, '结果为 6。
过程：
1. 优先级：自增/自减（单目）> 乘法 > 加法。
2. 先计算++x，x变为2，表达式中用2。
3. 计算--z，z变为2，表达式中用2。
4. 计算y++，表达式中用y原值2，然后y变为3。
5. 乘法：y++的值为2，乘以--z的值为2，得4。
6. 加法：++x的值2加上4得6。', '本题综合考察前置/后置自增自减的求值时机以及运算符优先级。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('92e7522f-89b1-5316-98eb-05d2d71ec7ca', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '分析以下代码的输出：
int a=5, b=2;
float c = a / b;
printf("%f", c);', 'coding', NULL, '输出为 2.000000。
分析：a/b是整数除法，结果为2（int），然后赋值给float c时隐式转换为2.0，所以输出2.000000。', '常见错误：误以为a/b会得到2.5，但实际上整数除法先执行，截断后再转换。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('768304b2-0360-5493-a7ad-bf285328b927', '99da1ba1-6f61-5901-9da6-8b9a3f783a3d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '编写一个表达式，判断整数n是否为偶数，要求使用位运算符，并说明优先级。', 'coding', NULL, '表达式： (n & 1) == 0

分析：
1. 位与运算符 & 优先级低于关系运算符 ==，所以必须加括号。
2. n & 1 取出最低位，若为0则偶数，为1则奇数。
3. 比较结果与0是否相等，相等为真（1），否则为假（0）。', '考察位运算符的使用及优先级问题，不加括号会导致错误顺序：n & 1 == 0 被解析为 n & (1==0)，即 n & 0，恒为0。', 'hard', NULL, NULL, '类型转换与优先级', '2026-07-05T11:58:37.680753+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('15e253ac-075f-57eb-b926-99a21cbfd21d', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，关于函数定义和调用的描述，正确的是？', 'choice', '["A. 函数定义必须放在所有函数调用之前", "B. 函数可以没有返回值，此时返回类型应写为void", "C. 函数调用时，形参的改变会影响实参的值", "D. 函数定义中参数列表可以为空，但圆括号不能省略"]', 'B', '选项A错误：函数可以先声明再定义，不一定定义在调用之前。选项B正确：无返回值的函数返回类型为void。选项C错误：C语言采用值传递，形参改变不影响实参。选项D错误：参数列表为空时圆括号不能省略，这是正确的，但题目问的是正确描述，B更直接准确。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6fbaa878-bf0b-5e97-a8d9-9da36af640b4', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '若有函数定义 int func(int a, int b) { return a + b; }，则调用 func(3, 5) 后返回的值是？', 'choice', '["A. 3", "B. 5", "C. 8", "D. 不确定"]', 'C', '函数 func 返回两个参数的和，3+5=8，因此返回值为8。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('778ba423-2c37-5ecd-bf7f-eb0482573a3f', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '关于函数原型声明的说法，错误的是？', 'choice', '["A. 函数原型可以省略参数名，只写参数类型", "B. 函数原型必须与函数定义的返回类型一致", "C. 函数原型可以放在调用之前，也可以放在调用之后", "D. 函数原型以分号结尾"]', 'C', '函数原型必须在函数调用之前声明，否则编译器无法识别该函数。选项C的说法错误。其他选项正确：原型可以省略参数名；返回类型必须一致；原型以分号结束。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('26b2925d-366c-5c7c-857a-b54bbe6e0358', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '以下哪个关键字用于表示函数不返回任何值？', 'choice', '["A. int", "B. void", "C. return", "D. null"]', 'B', 'void 表示函数没有返回值。int 是整型返回类型；return 是返回语句；null 在C语言中不是关键字。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('fc8c6caa-14be-534c-b624-be933c589945', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，函数调用时实参和形参之间的数据传递方式是？', 'choice', '["A. 地址传递", "B. 值传递", "C. 引用传递", "D. 双向传递"]', 'B', 'C语言中，函数调用默认采用值传递，将实参的值复制给形参，形参的修改不影响实参。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5dd76a68-1b5a-5160-b442-43287e5af881', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'C语言中，函数可以嵌套定义，即在一个函数内部定义另一个函数。', 'choice', '["A. 正确", "B. 错误"]', 'B', 'C语言不允许函数嵌套定义，但允许函数嵌套调用。函数定义必须放在全局作用域中。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('55e9fa0e-eafe-5f1e-a9e7-324a9daac55b', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '函数返回值的类型必须与函数定义中声明的返回类型一致。', 'choice', '["A. 正确", "B. 错误"]', 'A', '函数的返回值类型由函数头部的返回类型决定，return 语句中的表达式类型应与之匹配，否则可能发生隐式转换或编译警告。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5c26c752-38c6-52de-bf48-9e95306ba5a2', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '如果函数没有参数，定义时参数列表可以省略不写圆括号。', 'choice', '["A. 正确", "B. 错误"]', 'B', '即使函数没有参数，定义时也必须写圆括号，例如 void func()。省略圆括号是语法错误。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e57b4140-5c37-55f7-93e2-f5ca3704204d', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '函数调用时，实参的数量必须与形参的数量相同。', 'choice', '["A. 正确", "B. 错误"]', 'A', 'C语言要求实参与形参的数量一致（可变参数函数除外，如 printf，但普通函数必须一一对应）。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('44a4bdb1-93b6-54b5-9634-5b227fdb89ab', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '函数执行到 return 语句时，会立即结束当前函数的执行并返回调用点。', 'choice', '["A. 正确", "B. 错误"]', 'A', 'return 语句的作用是结束当前函数的执行，并将控制权和返回值（如果有）交还给调用函数。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8de81c1b-10f4-5ea8-8a72-dae6ef0e3a84', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，函数定义的一般形式为：返回类型 函数名(参数列表) { ___ }。', 'fill', NULL, '函数体', '花括号内的部分称为函数体，包含实现函数功能的语句。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a090e2b7-68c7-5864-8c7a-64697bbcc993', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'C语言中，函数调用时，实参向形参传递数据的方式是___传递。', 'fill', NULL, '值', '值传递将实参的值复制给形参，形参在函数内部作为局部变量使用，不影响实参。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('dcc13139-7eef-52b4-9b37-e55e24650f91', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '以下程序输出结果是___。
#include <stdio.h>
void swap(int x, int y) {
    int temp = x;
x = y;
y = temp;
}
int main() {
    int a = 3, b = 5;
swap(a, b);
printf("%d,%d", a, b);
return 0;
}', 'fill', NULL, '3,5', '由于C语言采用值传递，swap函数内部交换的是形参x和y的值，实参a和b不受影响，因此输出仍为3,5。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('aef5c9ce-699b-5138-b839-939a547d8da1', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '函数定义中，若返回类型为___，则函数可以没有return语句。', 'fill', NULL, 'void', 'void 函数不需要返回值，可以没有 return 语句，或者使用不带表达式的 return; 语句。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.059153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2a29ed19-7bf4-5956-bc16-76de6f43d510', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '编写一个C语言函数，判断一个整数是否为素数（质数）。要求：
1. 函数原型为 int isPrime(int n);
2. 如果n是素数返回1，否则返回0。
3. 在main函数中调用该函数，输入一个正整数，输出判断结果。', 'coding', NULL, '```c
#include <stdio.h>
int isPrime(int n) {
    if (n <= 1) return 0;
for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) return 0;
}
    return 1;
}
int main() {
    int num;
printf("请输入一个正整数: ");
scanf("%d", &num);
if (isPrime(num)) {
        printf("%d是素数\\n", num);
} else {
        printf("%d不是素数\\n", num);
}
    return 0;
}
```', '素数定义为大于1且只能被1和自身整除的自然数。函数 isPrime 先排除小于等于1的情况，然后从2遍历到sqrt(n)，若存在因子则不是素数。main函数中读取整数并调用isPrime，根据返回值输出结果。', 'easy', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.338864+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6687408c-d679-5c55-8ded-d9a057afc4bb', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '现有函数定义如下：
int multiply(int a, int b) {
    return a * b;
}
请写出该函数的原型声明，并说明在什么情况下必须使用函数原型。', 'coding', NULL, '函数原型声明：int multiply(int a, int b); 或 int multiply(int, int);
必须在函数调用之前声明原型的情况：当函数定义位于调用之后，或者函数定义在另一个文件中时，必须提前声明原型，否则编译器无法识别函数。', '函数原型告诉编译器函数的返回类型和参数类型，使得编译器可以正确生成调用代码并进行类型检查。如果函数定义在调用之前，则定义本身可当作声明。', 'medium', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.338864+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f41c6edb-f617-5668-a0dc-a2e4159dc60a', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '阅读以下程序，写出输出结果并解释原因。
#include <stdio.h>
int test(int x) {
    x = x + 10;
return x;
}
int main() {
    int a = 5;
int b = test(a);
printf("a=%d, b=%d\\n", a, b);
return 0;
}', 'coding', NULL, '输出结果：a=5, b=15
解释：调用test(a)时，实参a的值5被复制给形参x。函数内部将x修改为15，并返回15赋值给b。由于值传递，实参a不受影响，仍为5。', '本题考察值传递的特性。形参x是函数内部的局部变量，修改x不会影响实参a。因此a保持原值5，b得到返回值15。', 'medium', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.338864+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('7245f4ac-f66e-5de7-b08b-fc073e63daa6', '9ec67288-b3b7-562b-b50e-ea21f3c77c9d', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '编写一个函数，计算斐波那契数列的第n项（n从0开始，F(0)=0, F(1)=1）。要求使用递归实现。并分析递归调用的过程。', 'coding', NULL, '```c
#include <stdio.h>
int fib(int n) {
    if (n == 0) return 0;
if (n == 1) return 1;
return fib(n-1) + fib(n-2);
}
int main() {
    int n;
printf("请输入n: ");
scanf("%d", &n);
printf("F(%d)=%d\\n", n, fib(n));
return 0;
}
```
递归调用过程举例：计算fib(4)时，先调用fib(3)和fib(2)；fib(3)再调用fib(2)和fib(1)……最终逐层返回结果。', '递归函数每次调用自身解决规模更小的子问题，直到达到基准情形（n=0或n=1）。注意递归深度过大会导致栈溢出，实际应用时可用循环优化。', 'medium', NULL, NULL, '函数的定义与调用', '2026-07-05T11:58:41.338864+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('09fa3cb7-1bf3-567b-bc98-decb4f540601', '89353830-b249-587d-ab7f-1a4723c827be', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '在C语言中，用于打开文件的函数是？', 'choice', '["A. fopen()", "B. fclose()", "C. fread()", "D. fwrite()"]', 'A', 'fopen()是C语言中用于打开文件的函数，返回一个FILE指针；fclose()用于关闭文件；fread()和fwrite()分别用于读写文件数据。', 'easy', NULL, NULL, '文件的打开与关闭', '2026-07-05T11:58:42.458101+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1849933f-9856-5220-a94a-d1f847fdbe52', '89353830-b249-587d-ab7f-1a4723c827be', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'fopen()函数返回NULL表示什么？', 'choice', '["A. 文件打开成功", "B. 文件不存在或无法打开", "C. 文件内容为空", "D. 文件指针无效"]', 'B', 'fopen()在文件打开失败时返回NULL，常见原因包括文件不存在、权限不足或路径错误。因此必须检查返回值是否为NULL。', 'easy', NULL, NULL, '文件的打开与关闭', '2026-07-05T11:58:42.458101+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('22e0f27b-515f-5cdd-bdb8-0b03065c45c1', '89353830-b249-587d-ab7f-1a4723c827be', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '下列哪个模式用于以只写方式打开文件，若文件存在则清空其内容？', 'choice', '["A. \\"r\\"", "B. \\"w\\"", "C. \\"a\\"", "D. \\"r+\\""]', 'B', '"w"模式以只写方式打开文件，如果文件存在则清空内容，不存在则创建新文件。"r"为只读，"a"为追加，"r+"为读写。', 'easy', NULL, NULL, '文件的打开与关闭', '2026-07-05T11:58:42.458101+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('85f94d08-56d1-5c2d-bc7e-c7edaca77b42', '89353830-b249-587d-ab7f-1a4723c827be', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '关闭文件时，fclose()函数的主要作用不包括以下哪一项？', 'choice', '["A. 刷新缓冲区", "B. 释放文件描述符", "C. 删除文件", "D. 释放动态分配的内存"]', 'C', 'fclose()会刷新缓冲区、释放文件描述符和动态分配的内存，但不会删除文件本身。删除文件需要使用remove()函数。', 'easy', NULL, NULL, '文件的打开与关闭', '2026-07-05T11:58:42.458101+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('50d4ba42-bb51-595a-8801-e6586fd32230', '89353830-b249-587d-ab7f-1a4723c827be', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '若以追加模式"a"打开文件，写入数据时数据会写入到？', 'choice', '["A. 文件开头", "B. 文件末尾", "C. 文件中间", "D. 覆盖原有内容"]', 'B', '"a"模式以追加方式打开文件，写入操作总是在文件末尾进行，不会覆盖原有内容。如果文件不存在则创建新文件。', 'easy', NULL, NULL, '文件的打开与关闭', '2026-07-05T11:58:42.458101+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0c440514-57e7-561d-8ab6-c24b186a9813', '89353830-b249-587d-ab7f-1a4723c827be', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', 'fopen()函数打开文件成功后，返回的FILE指针可以直接用于读写操作。', 'choice', '["A. 正确", "B. 错误"]', 'A', 'fopen()成功返回FILE指针，该指针指向一个结构体，包含文件描述符和缓冲区信息，可用于后续的fread()、fwrite()、fprintf()等读写函数。', 'easy', NULL, NULL, '文件的打开与关闭', '2026-07-05T11:58:42.458101+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('72fec30c-207a-523d-bb85-2e006aa1084c', '89353830-b249-587d-ab7f-1a4723c827be', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '使用fclose()关闭文件后，FILE指针会被自动置为NULL。', 'choice', '["A. 正确", "B. 错误"]', 'B', 'fclose()仅释放资源，不会修改指针变量的值，指针仍指向原来的地址但已失效。需要手动将指针赋值为NULL以避免悬空指针。', 'easy', NULL, NULL, '文件的打开与关闭', '2026-07-05T11:58:42.458101+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ad039743-e992-5723-b4cd-51244c67e57a', '89353830-b249-587d-ab7f-1a4723c827be', '9c01a8fb-9ebc-50ae-b160-527f3928a7d1', '以"wb"模式打开文件表示以二进制方式写入，不会对换行符进行转换。', 'choice', '["A. 正确", "B. 错误"]', 'A', '"wb"是二进制写入模式，与文本模式不同，它不会对换行符（''\\n''）进行任何转换，直接按原样写入。', 'easy', NULL, NULL, '文件的打开与关闭', '2026-07-05T11:58:42.458101+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('01a475ee-7606-548f-9aef-1eb844ef3664', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The word "abandon" most likely means ______.', 'choice', '["A. 放弃", "B. 接受", "C. 拥抱", "D. 提升"]', 'A', '"abandon" 意为“放弃、遗弃”，是四级高频动词。选项A正确，其他选项与词义不符。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b8cdb341-a123-573f-bb07-96f25b7f90f4', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'Which of the following is the best synonym for "benefit"?', 'choice', '["A. Loss", "B. Advantage", "C. Damage", "D. Problem"]', 'B', '"benefit" 意为“利益、好处”，其同义词为 "advantage"。其他选项均为反义词或无关词。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('7382f075-df2c-5de2-b6e6-bf8fa4f95ea8', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'In the sentence "She managed to ______ the task on time," which word fits best?', 'choice', '["A. abandon", "B. achieve", "C. accept", "D. adjust"]', 'B', '根据句意“她设法按时______任务”，"achieve"（完成、实现）最符合语境。"abandon"（放弃）相反，"accept"（接受）和"adjust"（调整）不搭配。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ee7804b5-58ce-5065-902c-63cc9e3b523b', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'What does "access" mean in the phrase "gain access to the building"?', 'choice', '["A. 出口", "B. 通道", "C. 钥匙", "D. 权限"]', 'B', '"access" 在此语境中意为“通道、入口”，"gain access to" 表示“进入”。选项B正确。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c5f8017a-bbe1-5b2f-b566-fab37b8f1870', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The word "challenge" is closest in meaning to ______.', 'choice', '["A. 困难", "B. 挑战", "C. 改变", "D. 机会"]', 'B', '"challenge" 直接对应中文“挑战”，是四级核心名词。其他选项为混淆项。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('78c75d7d-93a1-5ac9-a678-54b7bd37da46', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The word "accommodate" can mean both "to provide lodging" and "to adapt to".', 'choice', '["A. 正确", "B. 错误"]', 'A', '"accommodate" 确实有“容纳、提供住宿”和“适应、调节”两种常见含义，是四级多义词。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4828c734-38b7-5bb5-826a-284b0172da0e', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '"Abandon" and "retain" are synonyms.', 'choice', '["A. 正确", "B. 错误"]', 'B', '"abandon" 意为“放弃”，"retain" 意为“保留”，两者是反义词，不是同义词。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('69a78618-dc05-5bfc-9fce-58edf273f7d5', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The prefix "a-" in "abnormal" means "not" or "without".', 'choice', '["A. 正确", "B. 错误"]', 'A', '前缀 "a-" 常表示“不、无”，如 "abnormal"（不正常的）、"amoral"（非道德的）。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8e3b710d-49bf-5a81-89a5-810a72e550f0', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '"Benefit" is only used as a noun in English.', 'choice', '["A. 正确", "B. 错误"]', 'B', '"benefit" 既可作名词（利益），也可作动词（受益于），如 "benefit from"。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('acde93a8-0a30-5a9a-bbe7-9cc0e6b02288', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The word "challenge" always has a negative connotation.', 'choice', '["A. 正确", "B. 错误"]', 'B', '"challenge" 可中性或正面，如 "a challenging job"（有挑战性的工作）常含积极意义。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('75b247eb-2fd4-5a8a-8cb1-c9abc9017c27', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The new policy aims to ______ (促进) economic growth.', 'fill', NULL, 'boost', '"boost" 意为“促进、推动”，是四级常考动词，符合句意。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8e72ef7a-a282-565c-a6a0-a894064ee4d8', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'It is important to ______ (获得) practical skills during college.', 'fill', NULL, 'acquire', '"acquire" 意为“获得（知识、技能）”，是四级核心动词，常用于学习语境。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('11935b70-4b42-5d2d-9e79-175f4d712734', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The hotel can ______ (容纳) up to 500 guests.', 'fill', NULL, 'accommodate', '"accommodate" 表示“容纳”，与数量搭配。注意拼写中两个c和两个m。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('54a3f925-4ca5-5ea4-9fc6-3a248a82b32a', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'We must ______ (评估) the situation before making a decision.', 'fill', NULL, 'assess', '"assess" 意为“评估、评价”，是四级正式用语，常与 situation, risk 等搭配。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d20a246e-d9ef-5f3e-b3e3-ae6a17e6d0e1', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The ______ (好处) of exercise are well known.', 'fill', NULL, 'benefits', '"benefits" 是 "benefit" 的复数形式，意为“好处、益处”。注意此处需用复数。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('52421c8a-2fe8-5fd5-b163-307685f71f2f', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请用所给单词的正确形式填空，并翻译整个句子：
The company decided to ______ (abandon / acceptance) the project due to lack of funds.
然后写出一个同义句替换划线部分。', 'coding', NULL, '填空答案：abandon
翻译：由于缺乏资金，公司决定放弃这个项目。
同义句：The company decided to give up the project due to lack of funds.', '第一步：根据语境“lack of funds”可知应选动词，"abandon" 意为“放弃”，"acceptance" 是名词“接受”，不符合。
第二步：翻译需注意“due to”译为“由于”。
第三步：同义替换使用短语 "give up" 代替 "abandon"。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e2e8967e-e5eb-5767-a5ea-18ea3208ed3b', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读下列句子，判断划线单词的含义，并写出它的反义词：
"The new policy will benefit the whole community." 划线词：benefit
然后，用该反义词造一个句子。', 'coding', NULL, '含义：利益，好处（动词时意为“使受益”）
反义词：harm / damage
造句：Pollution will harm the environment.', '第一步：根据句子结构，benefit 在此作动词，意为“使受益”。
第二步：常见反义词为 harm 或 damage。
第三步：造句需语法正确且语义通顺。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0ccd4d14-c9b4-577e-abd5-1cf01d04b29b', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请将下列单词按词性分类，并各造一个句子：
accelerate, challenge, access, beneficial, accommodation', 'coding', NULL, '动词：accelerate（加速），challenge（挑战），access（访问）
名词：challenge（挑战），access（通道），accommodation（住宿）
形容词：beneficial（有益的）
句子示例：
1. The car accelerated quickly. (动词)
2. This is a big challenge. (名词)
3. We have access to the library. (名词)
4. Regular exercise is beneficial. (形容词)
5. The hotel provides accommodation. (名词)', '注意单词的多词性特点：challenge 和 access 既可作动词也可作名词。需按不同词性分别造句。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c0cb94d4-eb92-5052-9224-d1282005f834', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在定语从句中，当先行词被形容词最高级修饰时，关系代词只能用that。', 'choice', '["A. 正确", "B. 错误"]', 'A', '先行词被形容词最高级、序数词或only、very等修饰时，关系代词通常用that，不用which或who。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b22922eb-abac-50f3-8d31-c88d34054957', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '“I wish I know the answer.” 这句话是语法正确的虚拟语气表达。', 'choice', '["A. 正确", "B. 错误"]', 'B', 'wish后的宾语从句用虚拟语气，表示与现在事实相反时，动词用过去式。know应改为knew。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f92025de-cbae-5f8f-8874-f012018fb9cc', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读短文，从括号中选择合适的单词填空：
Many students find it difficult to (1)______ (abandon / achieve) a balance between study and leisure. However, with proper planning, they can (2)______ (access / assess) their time more effectively. The (3)______ (benefit / challenge) of good time management is obvious.', 'coding', NULL, '(1) achieve  (2) assess  (3) benefit
完整短文：Many students find it difficult to achieve a balance between study and leisure. However, with proper planning, they can assess their time more effectively. The benefit of good time management is obvious.', '(1) "achieve a balance" 是固定搭配，意为“达到平衡”。(2) "assess time" 意为“评估时间”。(3) "benefit" 在此作名词，意为“好处”。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1c7dfbb8-ed73-56fb-b333-bcf4f1acf298', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请用单词 "accommodate" 的两个不同含义分别造句，并说明每个句子中该词的含义。', 'coding', NULL, '句1: This classroom can accommodate 50 students. 含义：容纳
句2: You should accommodate yourself to the new environment. 含义：适应', '"accommodate" 有两个常见义项：①容纳（及物动词，后接容量）；②适应（常接反身代词 + to）。造句时需体现不同搭配。', 'easy', NULL, NULL, '四级核心词汇(Part1: A-C)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('fbe2ae0d-c804-5eb0-be8b-a27795b1b9b6', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The professor asked the students to ______ the experiment results in front of the class.', 'choice', '["A. demonstrate", "B. decrease", "C. defend", "D. delay"]', 'A', 'demonstrate意为“展示、演示”，符合句意“教授要求学生向全班展示实验结果”。decrease（减少）、defend（防御）、delay（延迟）均不符合语境。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('12d5368c-6a5a-56c1-92df-743ef6a8653f', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'Solar energy is considered an ______ source of power because it produces little pollution.', 'choice', '["A. efficient", "B. elegant", "C. enormous", "D. essential"]', 'A', 'efficient意为“高效的”，符合句意“太阳能被认为是一种高效能源，因为其污染少”。elegant（优雅的）、enormous（巨大的）、essential（基本的）均不准确。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('07da435a-1fe3-5b7d-af4d-1da664bcc4af', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The new policy aims to ______ more job opportunities for young graduates.', 'choice', '["A. generate", "B. guarantee", "C. gather", "D. glance"]', 'A', 'generate意为“产生、创造”，符合句意“新政策旨在为年轻毕业生创造更多就业机会”。guarantee（保证）、gather（聚集）、glance（瞥见）均不符合。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d63bad52-582e-5664-a55d-9f504421051c', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'It is important to ______ on the key points rather than getting lost in details.', 'choice', '["A. focus", "B. fade", "C. float", "D. flow"]', 'A', 'focus on是固定搭配，意为“聚焦于”，符合句意“聚焦关键点很重要，而不是迷失在细节中”。fade（褪色）、float（漂浮）、flow（流动）均无此搭配。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b0dfc0b1-51f9-5b57-ab81-a9d55d023577', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The athlete''s ______ training allowed him to break the world record.', 'choice', '["A. generous", "B. gentle", "C. genuine", "D. gradual"]', 'C', 'genuine意为“真正的、真实的”，这里引申为“刻苦的、真正的训练”，符合句意。generous（慷慨的）、gentle（温和的）、gradual（逐渐的）均不贴切。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d42a8f67-436a-548f-865c-a4915789ff66', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The prefix ''de-'' in the word ''decrease'' means ''to increase''.', 'choice', '["A. 正确", "B. 错误"]', 'B', 'de-前缀常表示“向下、去除”，decrease意为“减少”，因此de-并不表示“增加”。题干说法错误。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('acf639bf-c32f-59d4-8f26-c00c3ef502bd', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '''Efficient'' and ''effective'' have exactly the same meaning and can be used interchangeably in all contexts.', 'choice', '["A. 正确", "B. 错误"]', 'B', 'efficient强调“高效、省时省力”，effective强调“有效果”，两者含义有区别，并非在所有语境中可互换。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('dfe319d2-ffb5-581b-b1e9-a67b02f3fb52', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The word ''generate'' shares the same Latin root ''gen-'' with ''gene'' and ''genius''.', 'choice', '["A. 正确", "B. 错误"]', 'A', 'generate、gene、genius都源自拉丁词根gen-，意为“产生、起源、种族”，因此说法正确。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('81902af4-fc10-5e11-affc-c70e83ed368d', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'In the sentence ''She glanced at the watch'', ''glanced'' means ''stared intently''.', 'choice', '["A. 正确", "B. 错误"]', 'B', 'glance意为“瞥一眼、快速看”，而stare意为“凝视、盯着看”，两者含义相反，故题干错误。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.321546+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('be8cda78-1250-5440-b14a-4a1f27057b4e', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The verb ''guarantee'' can be followed by an infinitive (to do) or a that-clause.', 'choice', '["A. 正确", "B. 错误"]', 'A', 'guarantee后常接不定式（guarantee to do）或that从句（guarantee that...），表示“保证做某事”或“保证……”，用法正确。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e79345fc-8845-5a2f-92e8-c56750bcb941', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'Many students find it hard to ______ (聚焦) on their homework when there is too much noise.', 'fill', NULL, 'focus', 'focus on意为“聚焦于”，句中需要动词原形，且与介词on搭配。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('185d72a1-ed5d-5662-bf09-6e03bc89d473', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The company offered a full money-back ______ (保证) if customers were not satisfied.', 'fill', NULL, 'guarantee', 'guarantee可作名词，意为“保证”，此处指“全额退款保证”。', 'easy', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('758047d4-dcce-5a0e-8d92-2e1d5597bdc1', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'To ______ (展示) the new software, the engineer ran a live demo.', 'fill', NULL, 'demonstrate', 'demonstrate意为“展示、演示”，不定式to后接动词原形。', 'medium', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('93f022c8-85e4-5e4a-bbcd-96269b0fb018', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The doctor advised him to ______ (减少) his intake of sugar and salt.', 'fill', NULL, 'decrease', 'decrease意为“减少”，符合句意“减少糖和盐的摄入”。', 'medium', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2b9431b7-ed96-5560-a5ba-c74843762343', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The wind farm can ______ (产生) enough electricity to power 10,000 homes.', 'fill', NULL, 'generate', 'generate意为“产生（电力）”，情态动词can后接动词原形。', 'medium', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e8a3ddb5-a5e4-5b3e-bf68-1c4ec7e6cdd6', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '“Not only he but also I am going to the party.” 这句话主谓一致是正确的。', 'choice', '["A. 正确", "B. 错误"]', 'A', 'not only...but also...遵循就近原则，谓语动词与最近的主语I保持一致，用am，正确。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('01230f5e-26f4-5845-ae3d-6a30c64f19d3', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'She usually _____ (go) to the library on weekends.', 'fill', NULL, 'goes', '主语为第三人称单数，一般现在时表示习惯，动词go加-es变为goes。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ee22dac3-0662-59c7-90bf-4011822911cf', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请用所给词汇（demonstrate, efficient, generate, focus, guarantee）各造一个句子，并说明每个句子中该词的含义和词性。', 'coding', NULL, '1. demonstrate (动词): The teacher demonstrated the chemical reaction in class. 含义：演示。
2. efficient (形容词): This new machine is more efficient than the old one. 含义：高效的。
3. generate (动词): The plant generates electricity from solar panels. 含义：产生。
4. focus (动词): You should focus on your studies instead of playing games. 含义：聚焦。
5. guarantee (动词): The store guarantees a full refund within 30 days. 含义：保证。', '每个词汇需正确使用其词性和含义，句子结构完整、语法正确。注意动词的时态和搭配，形容词的修饰对象要合理。', 'medium', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('535d879b-82fa-55a6-a906-623602a513ed', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读下列短文，从方框中选择合适的词填空（每个词限用一次）：demonstrate, efficient, generate, focus, guarantee.

The new solar farm can ______ (1) clean energy for the whole town. It is more ______ (2) than traditional power plants. The engineers will ______ (3) how the system works to the public next week. They also ______ (4) that the farm will operate for at least 20 years. The project''s main ______ (5) is on reducing carbon emissions.', 'coding', NULL, '(1) generate (2) efficient (3) demonstrate (4) guarantee (5) focus', '短文语境：太阳能发电厂“产生”清洁能源（generate），比传统电厂更“高效”（efficient），工程师将“展示”工作原理（demonstrate），并“保证”运营20年（guarantee），项目的“聚焦点”是减排（focus）。注意focus在此处作名词。', 'medium', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8a15450f-ae23-57c9-9bdf-d2c3de45410b', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请将下列句子翻译成英语，并注意使用本单元核心词汇（D-G）。
1. 这次实验证明了他的理论是正确的。
2. 这台新设备非常高效，能大幅减少能源消耗。
3. 政府承诺会创造更多就业机会。
4. 演讲者强调了团队合作的重要性。
5. 这家公司保证产品质量。', 'coding', NULL, '1. This experiment demonstrated that his theory is correct.
2. This new device is very efficient and can greatly decrease energy consumption.
3. The government guarantees to generate more job opportunities.
4. The speaker focused on the importance of teamwork.
5. This company guarantees the quality of its products.', '翻译时注意词汇选择：demonstrate（证明）、efficient（高效的）、decrease（减少）、guarantee（保证/承诺）、generate（创造）、focus on（强调/聚焦）。时态和搭配要正确。', 'medium', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f7cde8b6-1c2d-5497-8295-6552b56909a7', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '根据提示写一段80词左右的短文，要求使用以下词汇中的至少4个：demonstrate, efficient, generate, focus, guarantee, decrease, frequent, genuine.
提示：你正在介绍一款新型环保汽车。', 'coding', NULL, 'Our new eco-friendly car is designed to be highly efficient. It can generate enough power with less fuel, which helps decrease pollution. The manufacturer guarantees a five-year warranty. The design focuses on both safety and comfort. Test drives will demonstrate its excellent performance.', '短文使用了efficient（高效的）、generate（产生）、decrease（减少）、guarantee（保证）、focus on（聚焦）、demonstrate（展示）共6个词汇，符合要求。内容围绕环保汽车展开，逻辑连贯。', 'medium', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('554c4ab1-be91-5dd1-a1ba-756f4678b37b', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请分析下列句子中划线词汇的构词法，并写出其词根含义：
1. The company tried to **deregulate** the industry.
2. His speech was **exaggerated** and unrealistic.
3. The **genesis** of the project was a casual conversation.', 'coding', NULL, '1. deregulate: de-（去除）+ regulate（管制）→ 去除管制，即“放松管制”。
2. exaggerated: ex-（向外）+ agger（堆积）→ 向外堆积，即“夸张”。
3. genesis: gen-（产生、起源）+ -esis（名词后缀）→ 起源、开端。', '通过分析词根和词缀，可以推测生词含义。de-表示“去除”，ex-表示“向外”，gen-表示“产生、起源”。掌握这些构词规律有助于扩大词汇量。', 'medium', NULL, NULL, '四级核心词汇(Part2: D-G)', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('647804f4-be29-5753-8914-61cd1eb8114d', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '下列哪个句子中的动词形式正确体现了“一般现在时”表示习惯的用法？', 'choice', '["A. She go to school every day.", "B. She goes to school every day.", "C. She went to school every day.", "D. She is going to school every day."]', 'B', '一般现在时表示习惯性动作，主语为第三人称单数时，动词需加-s或-es。选项B中的goes符合规则。A缺少-s，C是过去时，D是现在进行时，均不表示习惯。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('05dae9f7-7fa3-5525-b9a9-305b8accd80a', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '以下哪个选项的被动语态结构是正确的？', 'choice', '["A. The book was wrote by him.", "B. The book was written by him.", "C. The book is wrote by him.", "D. The book written by him."]', 'B', '被动语态的正确结构是“be动词 + 过去分词”。write的过去分词是written，因此B正确。A和C使用了错误的形式wrote，D缺少be动词。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6e2b0f24-3b00-5f56-8f48-1550d8804538', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在“This is the house _____ I was born.”中，应填入哪个关系副词？', 'choice', '["A. which", "B. that", "C. where", "D. when"]', 'C', '定语从句中，先行词是地点（the house），且在从句中作地点状语，因此用关系副词where。which和that用于指物作主语或宾语，when用于时间。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c6d326b5-d50c-58a7-8ac0-5536723c504b', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '下列哪个句子主谓一致正确？', 'choice', '["A. The team are playing well.", "B. Everyone in the class have a book.", "C. Neither the teacher nor the students is ready.", "D. Mathematics are my favorite subject."]', 'A', '集合名词team在表示整体时用单数动词，但此处强调队员个体动作，用复数are可以接受，且为常见用法。B中everyone是单数，应改为has；C遵循就近原则，students是复数，应改为are；D中mathematics为单数学科，应改为is。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b227a7c4-fb09-55d1-ad27-8535d826564b', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '“If I _____ you, I would accept the offer.” 应填入什么词？', 'choice', '["A. am", "B. was", "C. were", "D. be"]', 'C', '这是虚拟语气，表示与现在事实相反，be动词统一用were，因此选C。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e8320320-8289-5c59-9d31-226983e5c4b4', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '“He has been to Beijing twice.” 这句话表示他曾经去过北京两次，且现在可能不在北京。', 'choice', '["A. 正确", "B. 错误"]', 'A', 'have been to表示“去过某地”，强调经历，现在不在该地。句子正确表达了该含义。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0f2b6b49-e83b-5cdd-ba1e-c57084d4f3a7', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '“The news are very exciting.” 这句话的语法是正确的。', 'choice', '["A. 正确", "B. 错误"]', 'B', 'news是不可数名词，谓语动词应用单数形式is，而不是are。正确句子应为“The news is very exciting.”', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d1328d5d-5942-5611-878c-a839d13ea385', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'The window _____ (break) by the boy yesterday.', 'fill', NULL, 'was broken', '根据yesterday可知是过去时，且window是动作承受者，用被动语态，结构为was + 过去分词，break的过去分词是broken。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('18bf40c5-333c-5d23-a666-1ad078e1fdae', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'I don’t know the reason _____ he left early.', 'fill', NULL, 'why', '定语从句中，先行词reason在从句中作原因状语，因此用关系副词why引导。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a34f0a5c-a79b-5fd4-861c-f5eeda9c3be3', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'Either the manager or his assistants _____ (be) responsible for the project.', 'fill', NULL, 'are', 'either...or...遵循就近原则，谓语动词与最近的assistants保持一致，assistants是复数，因此用are。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0783b70f-5fd4-5599-a51a-bb997fa44227', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', 'It is essential that every student _____ (finish) the assignment on time.', 'fill', NULL, 'finish', '在it is essential that引导的从句中，需要使用虚拟语气，动词用原形，因此填finish。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('374c7740-3a32-5cd4-8a1f-21985aa32c94', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请将下列句子改为被动语态，并说明每一步的变化："The students have completed the project."', 'coding', NULL, '参考答案：The project has been completed by the students.
步骤：
1. 找出宾语the project，将其变为主语。
2. 原句时态为现在完成时（have completed），被动语态结构为have/has been + 过去分词。
3. 原主语the students变为by the students。
4. 注意主谓一致：the project是单数，因此助动词用has。', '解题思路：被动语态转换时，先确定时态，再调整主宾位置。现在完成时的被动语态公式为：主语 + have/has been + 过去分词 + by + 原主语。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e9e66aaf-c573-5b4b-9c1d-50d6d666def0', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '分析以下复合句，指出主句、从句类型及引导词："I will wait until you finish your work."', 'coding', NULL, '参考答案：
- 主句：I will wait
- 从句：until you finish your work（时间状语从句）
- 引导词：until
- 从句功能：修饰主句的谓语动词wait，表示时间条件。', '解题思路：until引导的从句表示动作持续到某个时间点，在句中充当状语，属于时间状语从句。识别从句类型可通过引导词和从句在句中的作用判断。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('da45b773-584c-510a-8649-724bf0e6fefc', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请修改以下句子中的语法错误，并说明原因："He don''t like coffee, and his brother don''t neither."', 'coding', NULL, '参考答案：He doesn''t like coffee, and his brother doesn''t either.
修改原因：
1. 主语He是第三人称单数，否定应用doesn''t而非don''t。
2. 同样，his brother为单数，应用doesn''t。
3. 否定句中的“也”应用either，而非neither（neither本身表示否定，不与don''t连用）。', '解题思路：检查主谓一致（第三人称单数用doesn''t），以及否定句中的并列结构。neither用于肯定句表示“两者都不”，而either用于否定句。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8cd4c01c-8e8b-5200-a369-e1b7c5ce68b9', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '将下列中文句子翻译成英语，注意时态和主谓一致："我们班的学生每天早晨都读英语。"', 'coding', NULL, '参考答案：The students in our class read English every morning.
步骤：
1. 主语是“我们班的学生”，核心词为students（复数），谓语用原形read。
2. “每天早晨”表示习惯，用一般现在时。
3. 注意：in our class为介词短语修饰students，不影响主谓一致。', '解题思路：先确定主语和谓语，注意一般现在时的用法。复数主语students对应动词原形，时间状语every morning提示用一般现在时。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.627061+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e69a8248-3b07-5f82-b7c7-c5cb58f9b7d8', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请用定语从句合并以下两个句子，并说明引导词的选择理由："I met a man. His car was stolen."', 'coding', NULL, '参考答案：I met a man whose car was stolen.
步骤：
1. 确定先行词为a man。
2. 第二个句子中的his car与先行词是所有关系，因此用关系代词whose。
3. 合并后，whose car引导的定语从句修饰a man。', '解题思路：当从句中的名词与先行词有“所有”关系时，用whose引导。whose既可指人也可指物。', 'medium', NULL, NULL, '常见语法规则总结', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c397356b-4ca1-567d-8673-ba7ad56958ea', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '根据艾宾浩斯遗忘曲线，以下哪种复习方式最能有效减缓遗忘？', 'choice', '["A. 一次性长时间反复背诵", "B. 每天固定时间重复阅读", "C. 按照先密后疏的间隔进行复习", "D. 只在考试前集中复习"]', 'C', '艾宾浩斯遗忘曲线表明，遗忘在学习后立即开始，且先快后慢。因此，按照先密后疏的间隔复习（如学习后1小时、1天、3天、7天）能最有效地巩固记忆。一次性长时间背诵或每天固定重复效果较差，考前集中复习则违背了间隔复习原则。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('012ca804-ffae-5669-bf9b-e4403e9164fc', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '以下哪种记忆策略属于“深层编码”？', 'choice', '["A. 将单词抄写10遍", "B. 大声朗读单词拼写", "C. 用单词造句并联想场景", "D. 看着单词表反复默念"]', 'C', '深层编码是指对信息进行意义加工，建立丰富联想。用单词造句并联想场景能激活多个脑区，形成更强的神经连接。而抄写、朗读、默念都属于浅层编码，主要依赖机械重复，记忆效果较差。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('7ae931c3-f4d5-50c3-9fcf-e7a910dc5833', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '关于“提取练习”，下列哪项描述最准确？', 'choice', '["A. 提取练习就是反复阅读课文", "B. 提取练习是指主动回忆所学内容", "C. 提取练习等同于做大量选择题", "D. 提取练习只需要在脑中回想，不需要写出来"]', 'B', '提取练习是指主动从大脑中检索信息的过程，如自测、默写、口头复述等。研究表明，主动回忆比单纯重读更有效。做选择题是提取练习的一种形式，但并非全部；而脑中回想若不输出，效果会打折扣。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('af51f198-2a50-5173-9d19-09c92ccbfb26', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在记忆单词“abandon”时，使用“a（一个）+ band（乐队）+ on（在…上）→ 一个乐队在舞台上，但主唱突然放弃演出”这种记忆方法属于哪种技巧？', 'choice', '["A. 词根词缀法", "B. 联想法", "C. 分类记忆法", "D. 语境记忆法"]', 'B', '题干中通过将单词拆解为“a+band+on”并编造故事进行记忆，属于典型的联想法。联想法利用已有的知识或图像与单词建立联系，是一种深层编码策略。词根词缀法侧重词源，分类法按主题分组，语境法强调在句子中记忆，均与题干描述不同。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6326984a-604e-5078-b1ca-f80d68113731', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在长对话中，对话开头通常包含主题句，因此开头部分非常重要。', 'choice', '["A. 正确", "B. 错误"]', 'A', '长对话的开头往往直接点明话题或场景，是理解全文的关键，也是常见考点所在。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('fd0bcb9c-31d0-5c47-9a74-6a8562b34543', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '以下哪一项最符合“多感官参与”的词汇记忆方法？', 'choice', '["A. 只看单词书，不出声", "B. 听单词音频同时看拼写，并用手写一遍", "C. 只用手机App刷单词", "D. 与同学互相提问但不动笔"]', 'B', '多感官参与强调听觉、视觉、动觉协同作用。听音频（听觉）、看拼写（视觉）、手写（动觉）同时进行，能强化记忆痕迹。只阅读、只用App或只口头提问都只调动了部分感官，效果不如多感官协同。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('bf61e52d-012a-59c1-8d7d-336fa7bac0f5', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '记忆的本质是神经元的连接与强化，因此只要重复次数足够多，就一定能把单词记住。', 'choice', '["A. 正确", "B. 错误"]', 'B', '记忆的本质确实是神经元的连接与强化，但单纯机械重复（浅层编码）效果有限。大脑需要意义加工、联想、情景嵌入等深层编码才能建立牢固的神经连接。仅靠重复次数，不注重编码深度和提取练习，很容易陷入“背了忘”的循环。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6bc32d7b-180c-50bc-a2ed-08067501ad9b', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '将单词放入具体句子或故事中记忆，属于“情景嵌入”策略，能激活更多脑区。', 'choice', '["A. 正确", "B. 错误"]', 'A', '情景嵌入是指将单词置于有意义的语境（如句子、故事、对话）中，使单词与场景、情感、逻辑关联，从而激活视觉、听觉、语义等多个脑区。这比孤立记忆单词更有效，符合深层编码和情境学习原理。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ddfe4551-bbb8-5c88-9e89-010dc398cf19', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '艾宾浩斯遗忘曲线告诉我们，遗忘是先慢后快的，所以复习应该先疏后密。', 'choice', '["A. 正确", "B. 错误"]', 'B', '艾宾浩斯遗忘曲线表明，遗忘在学习后立即开始，且速度先快后慢。因此，复习策略应该是先密后疏，即在遗忘最快的时间点（如学习后几小时到一天内）及时复习，之后再逐渐拉长间隔。先疏后密会错过最佳巩固时机。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d02101e1-df94-55d5-ad3a-747e9e3739f9', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '词根词缀法只适合记忆长单词，对短单词没有帮助。', 'choice', '["A. 正确", "B. 错误"]', 'B', '词根词缀法同样适用于短单词。许多短单词也包含词根或词缀，例如“act”（行动）是词根，“react”（反应）中的“re-”是前缀。即使单词本身很短，了解其构词成分也有助于理解词义和派生词。因此，该方法对所有单词均有帮助。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('141653e2-819e-5fb5-9a17-5426abb34072', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在词汇记忆中，“提取练习”比“重复阅读”效果更好，因为前者需要主动回忆。', 'choice', '["A. 正确", "B. 错误"]', 'A', '大量认知心理学研究证实，主动回忆（提取练习）比被动重读更能巩固记忆。提取过程迫使大脑检索信息，强化神经连接，而重复阅读只是再次输入，容易产生“熟悉错觉”，实际记忆效果较弱。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ce0ba8d3-92fb-5774-ae29-91aea48b996f', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '艾宾浩斯遗忘曲线表明，信息在最初学习后迅速遗忘，但通过及时、有间隔的___可以显著减缓遗忘。', 'fill', NULL, '复习', '艾宾浩斯遗忘曲线揭示了遗忘的规律，而克服遗忘最有效的方法就是及时、有间隔的复习。复习能强化神经连接，将短期记忆转化为长期记忆。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('86604e61-be75-50da-a60f-0e2cb5a8ed1b', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '记忆技巧中，利用___（如造句、编故事）能将单词转化为有意义的记忆单元，属于深层编码。', 'fill', NULL, '语境', '将单词放入具体语境（如句子、故事）中记忆，可以激活更多脑区，建立语义联系，从而加深编码深度。这是词汇记忆的重要技巧之一。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('240c1ce7-a63f-5eac-98a1-ab1d55dec960', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '单词“unbelievable”由“un-”（不）、“believe”（相信）和“-able”（能…的）组成，这种记忆方法称为___法。', 'fill', NULL, '词根词缀', '词根词缀法通过分析单词的前缀、后缀和词根来理解词义，是高效的词汇记忆技巧。“un-”是否定前缀，“-able”是形容词后缀，组合起来就是“不可相信的”。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('37e647f5-5022-55cf-a73f-c370ca4c9e01', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '为了突破“背了忘、忘了背”的循环，应该将孤立的单词转化为有意义的、可关联的、___参与的记忆单元。', 'fill', NULL, '多感官', '多感官参与（如听、看、写、说）能激活多个脑区，强化记忆痕迹，是高效词汇记忆的重要策略。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d9fed84f-a06d-5197-b2ee-573bd378ff74', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在词汇记忆中，通过自测、默写等方式主动回忆所学内容，这种策略被称为___。', 'fill', NULL, '提取练习', '提取练习是指主动从大脑中检索信息，而非被动重读。研究表明，提取练习能显著提高长期记忆效果，是比重复阅读更有效的学习策略。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4ca8408b-a3d2-5ce1-b2b8-1f6cf05bfac4', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请运用至少两种词汇记忆技巧（如词根词缀法、联想法、语境法、多感官法等），详细说明如何记忆单词“conspicuous”（显眼的，引人注目的）。要求写出具体的记忆步骤，并解释为什么这些方法有效。', 'coding', NULL, '参考答案：
方法一：词根词缀法
- 拆解：con-（共同，加强）+ spic（看，词根）+ -uous（形容词后缀，表示“有…性质的”）→ 共同看、大家都看 → 显眼的。
- 步骤：先记住词根spic（看），再结合前缀后缀理解词义。
- 为什么有效：通过拆解，将长单词分解为有意义的构件，减轻记忆负担，同时有助于记忆同根词（如spectacular, inspect）。

方法二：联想法 + 多感官法
- 联想：con（像“看”）+ spic（谐音“四壁”）+ uous（谐音“有丝”）→ 想象一个人站在四面墙壁中间，身上缠着丝线，非常显眼。
- 多感官：一边想象画面（视觉），一边大声读出发音/kənˈspɪkjuəs/（听觉），同时手写几遍（动觉）。
- 为什么有效：联想法将抽象单词转化为生动图像，激活视觉脑区；多感官协同强化神经连接，提高记忆牢固度。

方法三：语境法
- 造句："The red dress made her conspicuous at the party."（那条红裙子使她在派对上很显眼。）
- 步骤：将单词放入具体场景，想象派对画面，并反复朗读句子。
- 为什么有效：语境提供了语义和情感线索，使单词与真实场景关联，提取时更容易激活。', '本题考察综合运用多种词汇记忆技巧的能力。词根词缀法利用构词规律，联想法利用图像和声音，语境法利用真实场景，多感官法调动多种输入通道。组合使用能发挥各自优势，实现深层编码和牢固记忆。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5604fbbd-3121-5d4b-a91d-c912d3a72d78', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听力篇章中，只要听懂每一个单词就能保证回答正确。', 'choice', '["A. 正确", "B. 错误"]', 'B', '篇章理解强调整体结构和信息整合，即使听懂每个单词，若抓不住逻辑关系和主旨仍可能答错。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('66151c27-846f-5069-a9d2-8155ee5953d5', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '小张计划在30天内记住300个四级高频词汇，但他经常感到“背了就忘”。请结合艾宾浩斯遗忘曲线和词汇记忆技巧，为他设计一个为期30天的学习计划，包括每日任务、复习安排以及至少三种具体记忆方法。要求计划可操作性强，并解释设计原理。', 'coding', NULL, '参考答案：
【总目标】30天掌握300词，每天学习10个新词。

【每日任务】
1. 早晨（30分钟）：学习10个新词。
   - 使用词根词缀法拆解单词（如“predict”= pre-前 + dict说）。
   - 为每个单词编写一个简短句子（语境法）。
   - 在单词卡片正面写单词、音标，背面写释义和例句。
2. 中午（10分钟）：复习当天新词（提取练习）：遮住释义，看单词回忆意思；遮住单词，看释义回忆拼写。
3. 傍晚（15分钟）：复习前一天及前3天学的单词（按间隔复习）。
4. 睡前（10分钟）：听当天单词的音频，同时闭眼回忆图像或句子（多感官法）。

【复习安排（基于艾宾浩斯曲线）】
- 第1次复习：学习后1小时（中午）。
- 第2次复习：学习后1天（第二天傍晚）。
- 第3次复习：学习后3天。
- 第4次复习：学习后7天。
- 第5次复习：学习后15天。
- 第6次复习：学习后30天（总复习）。
使用表格或App记录每个单词的复习时间点。

【具体记忆方法】
1. 词根词缀法：用于理解词义和派生词，如“invisible”= in-不 + vis看 + -ible能…的。
2. 联想法：将单词与熟悉的事物挂钩，如“ambulance”（救护车）谐音“俺不能死”。
3. 语境法：每个单词造一个与自己生活相关的句子，如“I need to memorize these words.”（memorize）。

【设计原理】
- 艾宾浩斯遗忘曲线：通过先密后疏的间隔复习，在遗忘的关键节点强化记忆，将短期记忆转化为长期记忆。
- 提取练习：每天中午和傍晚的自测迫使大脑主动检索，比重读更有效。
- 多感官与深层编码：词根词缀、联想、语境等方法增加了编码深度，建立更多神经连接。
- 分散学习：每天10个词比一次学100个效果好，符合“分散效应”。', '本题要求综合运用遗忘曲线和记忆技巧设计学习方案。计划需体现：间隔复习、提取练习、深层编码、多感官参与等原则。解析中要说明每个安排背后的记忆原理，展示理论与实践的结合。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4fe75cf1-3d40-51de-8c8a-faa2dc2de1da', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请从“词根词缀法”和“联想法”中各选一个例子，分别写出记忆单词“benevolent”（仁慈的）和“gossip”（八卦，闲聊）的具体步骤，并比较这两种方法的优缺点。', 'coding', NULL, '参考答案：

【词根词缀法记忆benevolent】
- 拆解：bene-（好，善）+ vol（意愿，意志）+ -ent（形容词后缀）→ 好意的 → 仁慈的。
- 步骤：①识别前缀bene-（如benefit好处）；②识别词根vol（如voluntary自愿的）；③组合理解词义。
- 优点：系统性强，能举一反三，记忆同根词（如benevolence）。
- 缺点：对词根不熟悉的学习者需要先积累词根知识，入门有门槛。

【联想法记忆gossip】
- 联想：go（去）+ s（谐音“是”）+ sip（小口喝）→ 想象一群人去咖啡馆，一边小口喝咖啡一边聊八卦。
- 步骤：①将单词拆成“go+s+sip”；②编造一个生动的场景；③边想象边重复单词发音。
- 优点：趣味性强，容易记住，适合形象思维好的学习者。
- 缺点：联想可能牵强，且对单词的构词规律帮助不大，难以扩展到其他单词。

【比较】
- 词根词缀法更科学系统，有助于理解单词的内在逻辑和派生关系，但需要一定基础。
- 联想法更灵活直观，适合快速记忆，但联想内容因人而异，有时不够准确。
- 实际使用中可结合：先尝试词根词缀分析，若单词构词复杂，再辅以联想。', '本题要求考生实际应用两种方法并比较。词根词缀法强调构词规律，联想法强调形象关联。解析需指出各自适用场景和局限性，并建议综合使用以取长补短。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e6ac4f27-ea89-5969-b7b8-53d57ee6a7fd', '4ca27ee3-847e-50b2-b612-dac16acbc906', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在四级考试中，你遇到了生词“ambiguous”（模糊的，模棱两可的）。请运用至少三种记忆技巧（如词根词缀、语境、多感官、提取练习等）来记住这个词，并设计一个包含该词的句子。最后，说明你将如何安排复习以巩固记忆（基于艾宾浩斯遗忘曲线）。', 'coding', NULL, '参考答案：

【记忆技巧】
1. 词根词缀法：ambi-（两边）+ gu（引导）+ -ous（形容词后缀）→ 两边引导的 → 方向不明确 → 模糊的。记住词根“amb-”表示“两边”（如ambidextrous双手灵巧的）。
2. 语境法：造句“His answer was ambiguous, so I didn''t know which option to choose.”（他的回答模棱两可，所以我不知道该选哪个选项。）想象考试中遇到这种情景。
3. 多感官法：①听单词音频/音标/æmˈbɪɡjuəs/；②看拼写并注意字母组合“ambi”；③手写3遍；④边写边小声读。
4. 提取练习：学完后1小时，遮住释义回忆词义；第二天遮住单词回忆拼写。

【复习安排（基于艾宾浩斯遗忘曲线）】
- 第1次复习：学习后1小时（提取练习）。
- 第2次复习：学习后1天（用单词造句并默写）。
- 第3次复习：学习后3天（在单词表中快速回忆）。
- 第4次复习：学习后7天（做包含该词的练习题）。
- 第5次复习：学习后15天（总复习，与其他易混词如“ambiguous”和“ambivalent”对比）。', '本题综合考查多种记忆方法的实际运用和复习策略。词根词缀帮助理解，语境提供场景，多感官强化痕迹，提取练习巩固记忆。复习安排遵循先密后疏原则，在遗忘关键点及时巩固，确保长期掌握。', 'hard', NULL, NULL, '词汇记忆方法与技巧', '2026-07-05T11:58:43.937254+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0cd87cc0-ce4f-52a7-8961-358e61246248', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在长对话听力中，听前阶段最重要的策略是什么？', 'choice', '["A. 立即开始听录音", "B. 快速浏览题目和选项，预测话题和问题类型", "C. 记住每个单词的发音", "D. 忽略选项，专注听对话"]', 'B', '听前利用题目选项和题干进行话题、场景和问题类型的预测，可以激活背景知识，提高听力效率。这是长对话听力技巧中的核心策略之一。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d7a8aad7-291f-521b-b810-a48537f0d4a9', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '长对话中，答案最常出现在哪个部分？', 'choice', '["A. 对话开头第一句", "B. 对话中间随意部分", "C. 问答环节以及转折词之后", "D. 对话结尾的告别语"]', 'C', '长对话中，问答环节和转折词（如but, however）之后往往是关键信息所在，答案常在此处出现。这是“关键信息优先”原则的体现。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('56126fa8-5fb3-57ec-9a88-d30804a175ae', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '下列哪项属于长对话听力中的干扰项类型？', 'choice', '["A. 与原文完全一致的信息", "B. 听到即选（原词复现但非答案）", "C. 对话中未提及的内容", "D. 与主题无关的细节"]', 'B', '“听到即选”是一种常见干扰项，即选项中出现了对话中的原词，但该词并非正确答案所在位置，容易误导考生。其他选项如完全一致的信息可能是正确答案，未提及或无关细节一般不会作为干扰项。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0a2f4d54-e9d8-5a63-8f1d-4911292a4aa1', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在长对话听力中，以下哪个词语最可能提示重要信息？', 'choice', '["A. maybe", "B. however", "C. sometimes", "D. usually"]', 'B', '转折词如however、but等通常引出与前面不同的观点或重要信息，是听力中需要重点捕捉的信号词。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('84437e75-0661-5911-8e19-1c8f710d4b91', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '长对话听力中，如果听到“first... second... third...”，这通常表示什么？', 'choice', '["A. 列举项，后面可能出题", "B. 对话即将结束", "C. 说话者在重复观点", "D. 无关紧要的细节"]', 'A', '列举词如first, second, third等提示信息点正在被分项列出，这些内容往往是考点或答案来源，需要重点记录。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('fa6834ec-ebba-540c-b24f-a719bb837d54', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '长对话听力中，只要听到选项中的原词出现，就可以直接选择该选项。', 'choice', '["A. 正确", "B. 错误"]', 'B', '这是“听到即选”的常见误区。原词复现可能是干扰项，正确答案往往需要理解上下文或经过同义替换，不能仅凭原词出现就选择。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('bb3eba9c-465b-5e20-8445-8f5f3bccb947', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听前预测可以帮助考生在听力过程中更快地定位关键信息。', 'choice', '["A. 正确", "B. 错误"]', 'A', '听前预测可以激活背景知识，使考生在听的过程中更有针对性，从而快速捕捉与预测相关的信息，提高答题效率。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1af2843f-4b0b-545d-9706-4bdc779e8ed8', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '线性表的顺序存储结构也称为___。', 'fill', NULL, '顺序表', '顺序存储的线性表通常简称为顺序表。', 'hard', NULL, NULL, '线性表的定义与操作', '2026-07-05T11:58:46.943153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9f068386-d6f9-54e9-8a72-09c1ec1141da', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '长对话听力中，笔记应该记录每一个单词，以确保不遗漏信息。', 'choice', '["A. 正确", "B. 错误"]', 'B', '长对话信息量大，记录每一个单词不现实且会分散注意力。应该记录关键词、数字、转折词后的内容等核心信息。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d2b60518-15f4-5f73-9844-00faeab0212e', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '“张冠李戴”是指将一个人的观点或行动错误地归到另一个人身上，这是一种常见的干扰项。', 'choice', '["A. 正确", "B. 错误"]', 'A', '在长对话中，不同说话者可能有不同观点，干扰项常将A的观点说成B的观点，考生需要仔细分辨谁说了什么。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2bbc5d41-7f50-5ce7-a513-7d3d32508c54', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '长对话听力中，听前利用___和___进行话题、场景和问题类型的预测。', 'fill', NULL, '题目选项, 题干', '听前预测是长对话听力技巧的重要步骤，通过浏览题目选项和题干，可以推测对话可能涉及的话题和问题类型，从而做好心理准备。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
